<?php
namespace App\Http\Controllers;
use App\Models\Account; use App\Models\Customer; use App\Models\Payment; use App\Models\PickupHold; use App\Models\PickupHoldAction; use App\Models\PickupHoldItem; use App\Models\Product; use App\Models\Purchase; use App\Models\PurchaseItem; use App\Models\Sale; use App\Models\SaleItem; use App\Models\Shop; use App\Models\Stock; use App\Models\Supplier; use App\Models\Variant; use App\Models\Warehouse;
use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\DB; use Illuminate\Support\Str; use Inertia\Inertia;
class PickupHoldController extends Controller {
    private function getUnitConversions(){return ['weight'=>['ton'=>1000,'kg'=>1,'gram'=>0.001,'pound'=>0.453592],'volume'=>['liter'=>1,'ml'=>0.001],'piece'=>['piece'=>1,'dozen'=>12,'box'=>1],'length'=>['meter'=>1,'cm'=>0.01,'mm'=>0.001]];}
    private function convertToBase($q,$u,$t){$c=$this->getUnitConversions(); return isset($c[$t?:'piece'][$u?:'piece'])?$q*$c[$t?:'piece'][$u?:'piece']:$q;}
    private function convertFromBase($q,$u,$t){$c=$this->getUnitConversions(); $v=$c[$t?:'piece'][$u?:'piece']??null; return $v?($q/$v):$q;}
    private function outletId(){ $u=Auth::user(); return $u->current_outlet_id??$u->outlet_id??null; }
    private function ownerId(){ $u=Auth::user(); return $u->owner_id??$u->id??null; }
    private function holdNo($d){return ($d==='outgoing'?'PHO':'PHI').'-'.now()->format('Ymd').'-'.strtoupper(Str::random(6));}
    private function saleNo(){return 'INV-PH-'.now()->format('Ymd').'-'.strtoupper(Str::random(6));}
    private function purchaseNo(){return 'PUR-PH-'.now()->format('Ymd').'-'.strtoupper(Str::random(6));}
    public function index(Request $request){$f=$request->only(['search','direction','status','shop_id','date_from','date_to']); $holds=PickupHold::with(['shop','items.product.brand','items.variant','items.warehouse'])->when($f['search']??null,function($q,$s){$q->where('hold_no','like',"%{$s}%")->orWhereHas('shop',fn($x)=>$x->where('name','like',"%{$s}%")->orWhere('phone','like',"%{$s}%"));})->when($f['direction']??null,fn($q,$v)=>$q->where('direction',$v))->when($f['status']??null,fn($q,$v)=>$q->where('status',$v))->when($f['shop_id']??null,fn($q,$v)=>$q->where('shop_id',$v))->latest()->paginate(15)->withQueryString(); return Inertia::render('Pickup/Holds/Index',['holds'=>$holds,'filters'=>$f,'shops'=>Shop::active()->get()]);}
    public function create(){return Inertia::render('Pickup/Holds/Create',['shops'=>Shop::active()->orderBy('name')->get(),'warehouses'=>Warehouse::where('is_active',true)->get(),'stocks'=>Stock::with(['warehouse','product.category','product.brand','variant','identifiers'])->where('quantity','>',0)->orderBy('created_at')->get(),'products'=>Product::with(['brand','category','variants'])->orderBy('name')->get(),'accounts'=>Account::where('is_active',true)->get(),'unitConversions'=>$this->getUnitConversions()]);}
    public function store(Request $request){$data=$request->validate(['shop_id'=>'required|exists:shops,id','direction'=>'required|in:outgoing,incoming','hold_date'=>'nullable|date','notes'=>'nullable|string','items'=>'required|array|min:1','items.*.product_id'=>'required|exists:products,id','items.*.variant_id'=>'nullable|exists:variants,id','items.*.warehouse_id'=>'nullable|exists:warehouses,id','items.*.stock_id'=>'nullable|exists:stocks,id','items.*.unit'=>'nullable|string','items.*.quantity'=>'required|numeric|min:0.0001','items.*.unit_price'=>'nullable|numeric|min:0','items.*.sale_price'=>'nullable|numeric|min:0']); return DB::transaction(function()use($data){$hold=PickupHold::create(['hold_no'=>$this->holdNo($data['direction']),'shop_id'=>$data['shop_id'],'direction'=>$data['direction'],'hold_date'=>$data['hold_date']??now()->toDateString(),'notes'=>$data['notes']??null,'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); foreach($data['items'] as $row){$p=Product::findOrFail($row['product_id']); $unit=$row['unit']??$p->default_unit??'piece'; $qty=(float)$row['quantity']; $base=$this->convertToBase($qty,$unit,$p->unit_type??'piece'); $unitPrice=(float)($row['unit_price']??0); $salePrice=(float)($row['sale_price']??$unitPrice); if($data['direction']==='outgoing'){ if(empty($row['stock_id'])) throw new \Exception('Stock is required for outgoing pickup.'); $stock=Stock::lockForUpdate()->findOrFail($row['stock_id']); $available=(float)($stock->available_base_quantity??$stock->base_quantity??$stock->quantity); if($base>$available) throw new \Exception("Not enough stock for {$p->name}"); $newBase=max(0,$available-$base); $newQty=$this->convertFromBase($newBase,$stock->unit??$unit,$p->unit_type??'piece'); $stock->update(['available_base_quantity'=>$newBase,'base_quantity'=>$newBase,'quantity'=>$newQty]); PickupHoldItem::create(['pickup_hold_id'=>$hold->id,'product_id'=>$p->id,'variant_id'=>$stock->variant_id,'warehouse_id'=>$stock->warehouse_id,'stock_id'=>$stock->id,'unit'=>$unit,'quantity'=>$qty,'base_quantity'=>$base,'remaining_quantity'=>$qty,'unit_price'=>$unitPrice?:$stock->purchase_price,'sale_price'=>$salePrice?:$stock->sale_price,'total_price'=>$qty*($salePrice?:$stock->sale_price),'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); }
            if($data['direction']==='incoming'){ $variantId=$row['variant_id']??null; if(!$variantId){$v=Variant::create(['product_id'=>$p->id,'attribute_values'=>[],'sku'=>($p->product_no?:'PRD-'.$p->id).'_DEFAULT_'.strtoupper(Str::random(4)),'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $variantId=$v->id;} if(empty($row['warehouse_id'])) throw new \Exception('Warehouse is required for incoming pickup.'); $stock=Stock::create(['warehouse_id'=>$row['warehouse_id'],'product_id'=>$p->id,'variant_id'=>$variantId,'quantity'=>$qty,'base_quantity'=>$base,'available_base_quantity'=>$base,'purchase_price'=>$unitPrice,'sale_price'=>$salePrice,'batch_no'=>'PIH-'.now()->format('Ymd').'-'.strtoupper(Str::random(6)),'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); PickupHoldItem::create(['pickup_hold_id'=>$hold->id,'product_id'=>$p->id,'variant_id'=>$variantId,'warehouse_id'=>$row['warehouse_id'],'stock_id'=>$stock->id,'unit'=>$unit,'quantity'=>$qty,'base_quantity'=>$base,'remaining_quantity'=>$qty,'unit_price'=>$unitPrice,'sale_price'=>$salePrice,'total_price'=>$qty*$unitPrice,'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); }} $hold->recalculateTotals(); return redirect()->route('pickup-holds.show',$hold->id)->with('success','Pickup hold created.');});}
    public function show(PickupHold $pickupHold){$pickupHold->load(['shop.customer','shop.supplier','items.product.brand','items.variant','items.warehouse','items.stock','actions.sale','actions.purchase']); return Inertia::render('Pickup/Holds/Show',['hold'=>$pickupHold,'accounts'=>Account::where('is_active',true)->get()]);}
    public function returnItem(Request $request, PickupHoldItem $item){$d=$request->validate(['quantity'=>'required|numeric|min:0.0001','notes'=>'nullable|string']); return DB::transaction(function()use($item,$d){$item=PickupHoldItem::with(['hold.shop','product','stock'])->lockForUpdate()->findOrFail($item->id); $hold=$item->hold; $qty=(float)$d['quantity']; if($qty>(float)$item->remaining_quantity) throw new \Exception('Quantity cannot exceed remaining.'); $base=$this->convertToBase($qty,$item->unit,$item->product->unit_type??'piece'); $stock=Stock::lockForUpdate()->findOrFail($item->stock_id); $cur=(float)($stock->available_base_quantity??$stock->base_quantity??$stock->quantity); if($hold->direction==='outgoing'){$new=$cur+$base;}else{if($base>$cur) throw new \Exception('Not enough stock to return.'); $new=max(0,$cur-$base);} $stock->update(['available_base_quantity'=>$new,'base_quantity'=>$new,'quantity'=>$this->convertFromBase($new,$stock->unit??$item->unit,$item->product->unit_type??'piece')]); $item->reduceRemaining($qty,'return'); PickupHoldAction::create(['pickup_hold_id'=>$hold->id,'pickup_hold_item_id'=>$item->id,'action_type'=>'return','quantity'=>$qty,'base_quantity'=>$base,'unit_price'=>$item->unit_price,'total_price'=>$qty*$item->unit_price,'notes'=>$d['notes']??null,'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $hold->recalculateTotals(); return back()->with('success','Returned successfully.');});}
    public function soldItem(Request $request, PickupHoldItem $item){$d=$request->validate(['quantity'=>'required|numeric|min:0.0001','unit_price'=>'nullable|numeric|min:0','paid_amount'=>'nullable|numeric|min:0','account_id'=>'nullable|exists:accounts,id','notes'=>'nullable|string']); return DB::transaction(function()use($item,$d){$item=PickupHoldItem::with(['hold.shop','product','variant'])->lockForUpdate()->findOrFail($item->id); $hold=$item->hold; $qty=(float)$d['quantity']; if($qty>(float)$item->remaining_quantity) throw new \Exception('Quantity cannot exceed remaining.'); $price=(float)($d['unit_price']??($hold->direction==='outgoing'?$item->sale_price:$item->unit_price)); $total=$qty*$price; $paid=(float)($d['paid_amount']??0); $accountId=$d['account_id']??null; if($paid>0&&!$accountId) throw new \Exception('Account required when paid amount > 0'); $base=$this->convertToBase($qty,$item->unit,$item->product->unit_type??'piece'); $sale=null; $saleItem=null; $purchase=null; $purchaseItem=null; if($hold->direction==='outgoing'){ $customer=$this->ensureCustomer($hold->shop); $sale=Sale::create(['customer_id'=>$customer->id,'invoice_no'=>$this->saleNo(),'sub_total'=>$total,'discount'=>0,'vat_tax'=>0,'grand_total'=>$total,'paid_amount'=>$paid,'due_amount'=>max(0,$total-$paid),'payment_type'=>$paid>0?'cash':'none','account_id'=>$accountId,'status'=>$paid>=$total?'paid':($paid>0?'partial':'pending'),'type'=>'inventory','sale_type'=>'pickup_hold','created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $saleItem=SaleItem::create(['sale_id'=>$sale->id,'product_id'=>$item->product_id,'variant_id'=>$item->variant_id,'warehouse_id'=>$item->warehouse_id,'stock_id'=>$item->stock_id,'quantity'=>$qty,'unit'=>$item->unit,'unit_quantity'=>$qty,'base_quantity'=>$base,'unit_price'=>$price,'total_price'=>$total,'shadow_unit_price'=>$price,'shadow_total_price'=>$total,'status'=>'completed','created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId(),'item_type'=>'pickup_hold']); $item->update(['sale_id'=>$sale->id]); }
            if($hold->direction==='incoming'){ $supplier=$this->ensureSupplier($hold->shop); $purchase=Purchase::create(['supplier_id'=>$supplier->id,'warehouse_id'=>$item->warehouse_id,'purchase_no'=>$this->purchaseNo(),'purchase_date'=>now()->toDateString(),'grand_total'=>$total,'paid_amount'=>$paid,'due_amount'=>max(0,$total-$paid),'payment_status'=>$paid>=$total?'paid':($paid>0?'partial':'unpaid'),'status'=>'completed','payment_type'=>$paid>0?'cash':'none','type'=>'local','created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $purchaseItem=PurchaseItem::create(['purchase_id'=>$purchase->id,'product_id'=>$item->product_id,'warehouse_id'=>$item->warehouse_id,'supplier_id'=>$supplier->id,'variant_id'=>$item->variant_id,'quantity'=>$qty,'unit'=>$item->unit,'unit_quantity'=>$qty,'base_quantity'=>$base,'unit_price'=>$price,'total_price'=>$total,'sale_price'=>$item->sale_price,'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $item->update(['purchase_id'=>$purchase->id]); }
            if($paid>0&&$accountId){$acc=Account::lockForUpdate()->findOrFail($accountId); if(method_exists($acc,'updateBalance')){$acc->updateBalance($paid,$hold->direction==='outgoing'?'deposit':'withdraw');} Payment::create(['sale_id'=>$sale?->id,'purchase_id'=>$purchase?->id,'customer_id'=>$sale?->customer_id,'supplier_id'=>$purchase?->supplier_id,'account_id'=>$accountId,'amount'=>$hold->direction==='outgoing'?$paid:-$paid,'shadow_amount'=>0,'payment_method'=>$acc->type??'cash','txn_ref'=>'PH-'.strtoupper(Str::random(8)),'note'=>$d['notes']??'Pickup hold payment','paid_at'=>now(),'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId(),'status'=>'completed']);}
            $item->reduceRemaining($qty,'sold'); PickupHoldAction::create(['pickup_hold_id'=>$hold->id,'pickup_hold_item_id'=>$item->id,'action_type'=>'sold','quantity'=>$qty,'base_quantity'=>$base,'unit_price'=>$price,'total_price'=>$total,'sale_id'=>$sale?->id,'sale_item_id'=>$saleItem?->id,'purchase_id'=>$purchase?->id,'purchase_item_id'=>$purchaseItem?->id,'notes'=>$d['notes']??null,'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $hold->recalculateTotals(); return back()->with('success','Sold/confirmed successfully.');});}
    private function ensureCustomer(Shop $shop){ if($shop->customer_id) return Customer::findOrFail($shop->customer_id); $c=Customer::create(['customer_name'=>$shop->name,'phone'=>$shop->phone,'address'=>$shop->address,'advance_amount'=>0,'due_amount'=>0,'is_active'=>1,'created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $shop->update(['customer_id'=>$c->id,'type'=>$shop->supplier_id?'both':'customer']); return $c; }
    private function ensureSupplier(Shop $shop){ if($shop->supplier_id) return Supplier::findOrFail($shop->supplier_id); $s=Supplier::create(['name'=>$shop->name,'contact_person'=>$shop->owner_name,'email'=>$shop->email,'phone'=>$shop->phone,'company'=>$shop->company,'address'=>$shop->address,'advance_amount'=>0,'due_amount'=>0,'is_active'=>1,'type'=>'local','created_by'=>Auth::id(),'outlet_id'=>$this->outletId(),'owner_id'=>$this->ownerId()]); $shop->update(['supplier_id'=>$s->id,'type'=>$shop->customer_id?'both':'supplier']); return $s; }
}
